});

let model;

class PrivacyPreservingPredictor {
  constructor(modelInstance, config) {
    this.model = modelInstance;
    this.config = config;
  }

  // Differential privacy: Laplace mechanism
  addLaplaceNoise(value) {
    if (!this.config.differentialPrivacy.noiseEnabled) return value;

    const { sensitivity, epsilon } = this.config.differentialPrivacy;
    const scale = sensitivity / epsilon;
    const u = Math.random() - 0.5;
    const noise = -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
    return Math.max(0, Math.min(1, value + noise));
  }

  // Temperature scaling to reduce overconfidence (mitigates membership inference)
  applyTemperatureScaling(logits, temperature = 2.0) {
    const scaledLogits = logits.map(l => l / temperature);
    const maxLogit = Math.max(...scaledLogits);
    const expLogits = scaledLogits.map(l => Math.exp(l - maxLogit));
    const sumExp = expLogits.reduce((a, b) => a + b, 0);
    return expLogits.map(e => e / sumExp);
  }

  // Label smoothing effect simulation
  smoothProbabilities(probs, smoothingFactor = 0.1) {
    const numClasses = probs.length;
    const uniform = 1 / numClasses;
    return probs.map(p => (1 - smoothingFactor) * p + smoothingFactor * uniform);
  }

  // Quantize to reduce precision leakage
  quantize(value) {
    const factor = Math.pow(10, this.config.outputFiltering.precision);
    return Math.round(value * factor) / factor;
  }

  async predict(inputData) {
    const tensor = tf.tensor2d([inputData]);

    try {
      // Get raw predictions
      const prediction = this.model.predict(tensor);
      const rawProbs = await prediction.array();
      prediction.dispose();

      // Step 1: Temperature scaling (reduces membership inference accuracy)
      const scaledProbs = this.applyTemperatureScaling(
        rawProbs[0].map(p => Math.log(p + 1e-10))
      );

      // Step 2: Label smoothing effect
      const smoothedProbs = this.smoothProbabilities(scaledProbs);

      // Step 3: Add differential privacy noise
      const noisedProbs = smoothedProbs.map(p => this.addLaplaceNoise(p));

      // Step 4: Normalize after noise
      const sum = noisedProbs.reduce((a, b) => a + b, 0);
      const normalizedProbs = noisedProbs.map(p => p / sum);

      // Step 5: Top-k filtering
      const indexed = normalizedProbs.map((prob, idx) => ({ prob, idx }));
      indexed.sort((a, b) => b.prob - a.prob);
      const topK = indexed.slice(0, this.config.outputFiltering.topK);

      // Step 6: Quantize final outputs
      return topK.map(item => ({
        classId: item.idx,
        confidence: this.quantize(item.prob)
      }));

    } finally {
      tensor.dispose();
    }
  }
}

// Anomaly detection for attack patterns
class QueryPatternAnalyzer {
  constructor(redisClient, config) {
    this.redis = redisClient;
    this.config = config;
  }

  // Compute input hash for similarity detection
  computeInputHash(inputData, precision = 1) {
    const quantized = inputData.map(v => Math.round(v * precision) / precision);
    return crypto.createHash('sha256').update(JSON.stringify(quantized)).digest('hex');
  }

  // Detect systematic query patterns (model inversion signature)
  async detectQueryPattern(clientId, inputData) {
    const coarseHash = this.computeInputHash(inputData, 1);
    const fineHash = this.computeInputHash(inputData, 10);

    const patternKey = `attack:pattern:${clientId}`;
    const now = Date.now();

    // Store query with timestamp
    await this.redis.zadd(patternKey, now, `${coarseHash}:${fineHash}`);

    // Remove old queries outside window
    const windowStart = now - this.config.anomalyDetection.queryPatternWindow;
    await this.redis.zremrangebyscore(patternKey, 0, windowStart);

    // Count similar queries (same coarse hash)
    const recentQueries = await this.redis.zrangebyscore(patternKey, windowStart, now);
    const similarQueries = recentQueries.filter(q => q.startsWith(coarseHash));

    // Detect incremental probing (characteristic of gradient estimation)
    const incrementalProbing = await this.detectIncrementalProbing(clientId, inputData);

    return {
      similarQueryCount: similarQueries.length,
      isAnomaly: similarQueries.length > this.config.anomalyDetection.maxSimilarQueries,
      incrementalProbing,
      riskScore: this.calculateRiskScore(similarQueries.length, incrementalProbing)
    };
  }

  async detectIncrementalProbing(clientId, inputData) {
    const probeKey = `attack:probe:${clientId}`;
    const inputStr = JSON.stringify(inputData);

    // Get recent inputs
    const recentInputs = await this.redis.lrange(probeKey, 0, 99);
    await this.redis.lpush(probeKey, inputStr);
    await this.redis.ltrim(probeKey, 0, 99);
    await this.redis.expire(probeKey, 3600);

    if (recentInputs.length < 10) return false;

    // Check for single-dimension changes (gradient probing pattern)
    let singleDimChanges = 0;
    const currentInput = inputData;

    for (const recentStr of recentInputs.slice(0, 20)) {
      const recentInput = JSON.parse(recentStr);
      let diffCount = 0;

      for (let i = 0; i < currentInput.length; i++) {
        if (Math.abs(currentInput[i] - recentInput[i]) > 0.001) {
          diffCount++;
        }
      }

      if (diffCount === 1) singleDimChanges++;
    }

    return singleDimChanges > 10; // High rate of single-dimension changes = probing
  }

  calculateRiskScore(similarCount, incrementalProbing) {
    let score = 0;
    score += Math.min(similarCount / 10, 5); // Max 5 points for similar queries
    score += incrementalProbing ? 5 : 0;
    return Math.min(score, 10);
  }
}

// Distributed rate limiter with sliding window
class DistributedRateLimiter {
  constructor(redisClient, config) {
    this.redis = redisClient;
    this.config = config;
  }

  async checkLimit(clientId) {
    const key = `ratelimit:${clientId}`;
    const now = Date.now();
    const windowStart = now - this.config.rateLimit.windowMs;

    // Remove old entries
    await this.redis.zremrangebyscore(key, 0, windowStart);

    // Count requests in window
    const requestCount = await this.redis.zcard(key);

    if (requestCount >= this.config.rateLimit.maxRequests) {
      return { allowed: false, remaining: 0, resetTime: windowStart + this.config.rateLimit.windowMs };
    }

    // Check burst limit (requests in last 1 second)
    const burstStart = now - 1000;
    const burstCount = await this.redis.zcount(key, burstStart, now);

    if (burstCount >= this.config.rateLimit.burstLimit) {
      return { allowed: false, remaining: this.config.rateLimit.maxRequests - requestCount, burst: true };
    }

    // Add current request
    await this.redis.zadd(key, now, `${now}:${crypto.randomBytes(4).toString('hex')}`);
    await this.redis.expire(key, Math.ceil(this.config.rateLimit.windowMs / 1000));

    return { 
      allowed: true, 
      remaining: this.config.rateLimit.maxRequests - requestCount - 1 
    };
  }
}

