// Laplace mechanism with configurable epsilon
addLaplaceNoise(value) {
  const scale = this.config.differentialPrivacy.sensitivity / 
                this.config.differentialPrivacy.epsilon;
  const u = Math.random() - 0.5;
  const noise = -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
  return Math.max(0, Math.min(1, value + noise));
}
```

