  static validateInput(input, requestId) {
    if (typeof input !== 'string') {
      return { valid: false, reason: 'Invalid input type' };
    }

    if (input.length > SECURITY_CONFIG.maxInputLength) {
      return { valid: false, reason: 'Input too long' };
