      if (pattern.test(input)) {
        AISecurityLogger.log('PROMPT_INJECTION_ATTEMPT', {
          requestId,
          pattern: pattern.toString(),
          inputHash: crypto.createHash('sha256').update(input).digest('hex').slice(0, 16)
        });
        return { valid: false, reason: 'Potentially malicious input detected' };
