    const sanitized = content
      .slice(0, maxLength)
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')  // Remove control chars
      .replace(/```/g, '\`\`\`');  // Escape code blocks

