    const data = await this.redis.get(`conv:${sessionId}`);
    if (!data) return { messages: [], metadata: {} };

    const conversation = JSON.parse(data);

    // Enforce turn limit
    if (conversation.messages.length > SECURITY_CONFIG.maxConversationTurns * 2) {
      conversation.messages = conversation.messages.slice(-SECURITY_CONFIG.maxConversationTurns * 2);
    }

    return conversation;
