    // Trim old messages if context too large
    while (totalLength > SECURITY_CONFIG.maxContextLength && conversation.messages.length > 2) {
      conversation.messages.splice(1, 2);  // Remove oldest user/assistant pair (keep system)
    }

    await this.redis.setex(
      `conv:${sessionId}`,
      SECURITY_CONFIG.sessionTTL,
      JSON.stringify(conversation)
    );
  }

  async clearConversation(sessionId) {
    await this.redis.del(`conv:${sessionId}`);
  }
