  const prediction = model.predict(tensor);
  const probabilities = await prediction.array();

  const topClass = probabilities[0].indexOf(Math.max(...probabilities[0]));
  let confidence = probabilities[0][topClass];

  // DEFENSE 1: Add differential privacy noise
  confidence = addDifferentialPrivacyNoise(confidence);
  confidence = Math.max(0, Math.min(1, confidence));  // Clamp to [0,1]

  // DEFENSE 2: Limit precision
  confidence = parseFloat(confidence.toFixed(CONFIDENCE_PRECISION));

  // DEFENSE 3: Threshold low-confidence predictions
  if (confidence < CONFIDENCE_THRESHOLD) {
    return res.json({
      prediction: 'uncertain',
      confidence_level: 'low',
      request_id: crypto.randomUUID()
    });
  }

  // DEFENSE 4: Return discretized confidence only
  res.json({
